#!/usr/bin/env node

'use strict';

const path = require('path');
const { spawnSync } = require('child_process');

const SUBCOMMANDS = {
	'migrate-to-v2': 'migrate-to-v2.js',
	'report-react19-consumer-gaps': 'report-react19-consumer-gaps.js',
};

const argv = process.argv.slice(2);
const cmd = argv[0];

function printHelp() {
	console.log(`
Usage: design-system-react <command> [options]

Commands:
  migrate-to-v2                 Отчёт и миграция на v2 (флаг --fix — применить правки)
  report-react19-consumer-gaps  Отчёт по типичным проблемам перехода на React 19

Examples:
  npx design-system-react migrate-to-v2
  npx design-system-react migrate-to-v2 --fix
  npx design-system-react report-react19-consumer-gaps --ignore "vendor,legacy"
`);
}

if (!cmd || cmd === '-h' || cmd === '--help') {
	printHelp();
	process.exit(!cmd ? 1 : 0);
}

const scriptName = SUBCOMMANDS[cmd];
if (!scriptName) {
	console.error(`Неизвестная команда: ${cmd}\n`);
	printHelp();
	process.exit(1);
}

const scriptPath = path.join(__dirname, scriptName);
const childArgs = argv.slice(1);
const result = spawnSync(process.execPath, [scriptPath, ...childArgs], {
	stdio: 'inherit',
	env: process.env,
});

process.exit(result.status === null ? 1 : result.status);